"""
Parameterized generator for GH210_core_147527.

Source PR:    https://github.com/home-assistant/core/pull/147527
Source Issue: https://github.com/home-assistant/core/issues/136419

Seed varies: renames 'after' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH210_core_147527'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH210_core_147527'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('after', 'after' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH210_core_147527',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'home-assistant/core',
                "pr_number": 147527,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/home-assistant/core/pull/147527",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'homeassistant/components/derivative/sensor.py': '"""Numeric derivative of data coming from a source sensor over time."""\n\nfrom __future__ import annotations\n\nfrom datetime import datetime, timedelta\nfrom decimal import Decimal, DecimalException, InvalidOperation\nimport logging\n\nimport voluptuous as vol\n\nfrom homeassistant.components.sensor import (\n    ATTR_STATE_CLASS,\n    PLATFORM_SCHEMA as SENSOR_PLATFORM_SCHEMA,\n    RestoreSensor,\n    SensorEntity,\n    SensorStateClass,\n)\nfrom homeassistant.config_entries import ConfigEntry\nfrom homeassistant.const import (\n    ATTR_UNIT_OF_MEASUREMENT,\n    CONF_NAME,\n    CONF_SOURCE,\n    STATE_UNAVAILABLE,\n    STATE_UNKNOWN,\n    UnitOfTime,\n)\nfrom homeassistant.core import (\n    CALLBACK_TYPE,\n    Event,\n    EventStateChangedData,\n    EventStateReportedData,\n    HomeAssistant,\n    State,\n    callback,\n)\nfrom homeassistant.helpers import config_validation as cv, entity_registry as er\nfrom homeassistant.helpers.device import async_entity_id_to_device\nfrom homeassistant.helpers.entity_platform import (\n    AddConfigEntryEntitiesCallback,\n    AddEntitiesCallback,\n)\nfrom homeassistant.helpers.event import (\n    async_call_later,\n    async_track_state_change_event,\n    async_track_state_report_event,\n)\nfrom homeassistant.helpers.typing import ConfigType, DiscoveryInfoType\n\nfrom .const import (\n    CONF_MAX_SUB_INTERVAL,\n    CONF_ROUND_DIGITS,\n    CONF_TIME_WINDOW,\n    CONF_UNIT,\n    CONF_UNIT_PREFIX,\n    CONF_UNIT_TIME,\n)\n\n_LOGGER = logging.getLogger(__name__)\n\nATTR_SOURCE_ID = "source"\n\n# SI Metric prefixes\nUNIT_PREFIXES = {\n    None: 1,\n    "n": 1e-9,\n    "μ": 1e-6,\n    "m": 1e-3,\n    "k": 1e3,\n    "M": 1e6,\n    "G": 1e9,\n    "T": 1e12,\n}\n\n# SI Time prefixes\nUNIT_TIME = {\n    UnitOfTime.SECONDS: 1,\n    UnitOfTime.MINUTES: 60,\n    UnitOfTime.HOURS: 60 * 60,\n    UnitOfTime.DAYS: 24 * 60 * 60,\n}\n\nDEFAULT_ROUND = 3\nDEFAULT_TIME_WINDOW = 0\n\nPLATFORM_SCHEMA = SENSOR_PLATFORM_SCHEMA.extend(\n    {\n        vol.Optional(CONF_NAME): cv.string,\n        vol.Required(CONF_SOURCE): cv.entity_id,\n        vol.Optional(CONF_ROUND_DIGITS, default=DEFAULT_ROUND): vol.Coerce(int),\n        vol.Optional(CONF_UNIT_PREFIX, default=None): vol.In(UNIT_PREFIXES),\n        vol.Optional(CONF_UNIT_TIME, default=UnitOfTime.HOURS): vol.In(UNIT_TIME),\n        vol.Optional(CONF_UNIT): cv.string,\n        vol.Optional(CONF_TIME_WINDOW, default=DEFAULT_TIME_WINDOW): cv.time_period,\n        vol.Optional(CONF_MAX_SUB_INTERVAL): cv.positive_time_period,\n    }\n)\n\n\ndef _is_decimal_state(state: str) -> bool:\n    try:\n        Decimal(state)\n    except (InvalidOperation, TypeError):\n        return False\n    else:\n        return True\n\n\nasync def async_setup_entry(\n    hass: HomeAssistant,\n    config_entry: ConfigEntry,\n    async_add_entities: AddConfigEntryEntitiesCallback,\n) -> None:\n    """Initialize Derivative config entry."""\n    registry = er.async_get(hass)\n    # Validate + resolve entity registry id to entity_id\n    source_entity_id = er.async_validate_entity_id(\n        registry, config_entry.options[CONF_SOURCE]\n    )\n\n    if max_sub_interval_dict := config_entry.options.get(CONF_MAX_SUB_INTERVAL, None):\n        max_sub_interval = cv.time_period(max_sub_interval_dict)\n    else:\n        max_sub_interval = None\n\n    derivative_sensor = DerivativeSensor(\n        hass,\n        name=config_entry.title,\n        round_digits=int(config_entry.options[CONF_ROUND_DIGITS]),\n        source_entity=source_entity_id,\n        time_window=cv.time_period_dict(config_entry.options[CONF_TIME_WINDOW]),\n        unique_id=config_entry.entry_id,\n        unit_of_measurement=None,\n        unit_prefix=config_entry.options.get(CONF_UNIT_PREFIX),\n        unit_time=config_entry.options[CONF_UNIT_TIME],\n        max_sub_interval=max_sub_interval,\n    )\n\n    async_add_entities([derivative_sensor])\n\n\nasync def async_setup_platform(\n    hass: HomeAssistant,\n    config: ConfigType,\n    async_add_entities: AddEntitiesCallback,\n    discovery_info: DiscoveryInfoType | None = None,\n) -> None:\n    """Set up the derivative sensor."""\n    derivative = DerivativeSensor(\n        hass,\n        name=config.get(CONF_NAME),\n        round_digits=config[CONF_ROUND_DIGITS],\n        source_entity=config[CONF_SOURCE],\n        time_window=config[CONF_TIME_WINDOW],\n        unit_of_measurement=config.get(CONF_UNIT),\n        unit_prefix=config[CONF_UNIT_PREFIX],\n        unit_time=config[CONF_UNIT_TIME],\n        unique_id=None,\n        max_sub_interval=config.get(CONF_MAX_SUB_INTERVAL),\n    )\n\n    async_add_entities([derivative])\n\n\nclass DerivativeSensor(RestoreSensor, SensorEntity):\n    """Representation of a derivative sensor."""\n\n    _attr_translation_key = "derivative"\n    _attr_should_poll = False\n\n    def __init__(\n        self,\n        hass: HomeAssistant,\n        *,\n        name: str | None,\n        round_digits: int,\n        source_entity: str,\n        time_window: timedelta,\n        unit_of_measurement: str | None,\n        unit_prefix: str | None,\n        unit_time: UnitOfTime,\n        max_sub_interval: timedelta | None,\n        unique_id: str | None,\n    ) -> None:\n        """Initialize the derivative sensor."""\n        self._attr_unique_id = unique_id\n        self.device_entry = async_entity_id_to_device(\n            hass,\n            source_entity,\n        )\n        self._sensor_source_id = source_entity\n        self._round_digits = round_digits\n        self._attr_native_value = round(Decimal(0), round_digits)\n        # List of tuples with (timestamp_start, timestamp_end, derivative)\n        self._state_list: list[tuple[datetime, datetime, Decimal]] = []\n        self._last_valid_state_time: tuple[str, datetime] | None = None\n\n        self._attr_name = name if name is not None else f"{source_entity} derivative"\n        self._attr_extra_state_attributes = {ATTR_SOURCE_ID: source_entity}\n\n        if unit_of_measurement is None:\n            final_unit_prefix = "" if unit_prefix is None else unit_prefix\n            self._unit_template = f"{final_unit_prefix}{{}}/{unit_time}"\n            # we postpone the definition of unit_of_measurement to later\n            self._attr_native_unit_of_measurement = None\n        else:\n            self._attr_native_unit_of_measurement = unit_of_measurement\n\n        self._unit_prefix = UNIT_PREFIXES[unit_prefix]\n        self._unit_time = UNIT_TIME[unit_time]\n        self._time_window = time_window.total_seconds()\n        self._max_sub_interval: timedelta | None = (\n            None  # disable time based derivative\n            if max_sub_interval is None or max_sub_interval.total_seconds() == 0\n            else max_sub_interval\n        )\n        self._cancel_max_sub_interval_exceeded_callback: CALLBACK_TYPE = (\n            lambda *args: None\n        )\n\n    def _calc_derivative_from_state_list(self, current_time: datetime) -> Decimal:\n        def calculate_weight(start: datetime, end: datetime, now: datetime) -> float:\n            window_start = now - timedelta(seconds=self._time_window)\n            return (end - max(start, window_start)).total_seconds() / self._time_window\n\n        derivative = Decimal("0.00")\n        for start, end, value in self._state_list:\n            weight = calculate_weight(start, end, current_time)\n            derivative = derivative + (value * Decimal(weight))\n\n        _LOGGER.debug(\n            "%s: Calculated new derivative as %f from %d segments",\n            self.entity_id,\n            derivative,\n            len(self._state_list),\n        )\n\n        return derivative\n\n    def _prune_state_list(self, current_time: datetime) -> None:\n        # filter out all derivatives older than `time_window` from our window list\n        old_len = len(self._state_list)\n        self._state_list = [\n            (time_start, time_end, state)\n            for time_start, time_end, state in self._state_list\n            if (current_time - time_end).total_seconds() < self._time_window\n        ]\n        _LOGGER.debug(\n            "%s: Pruned %d elements from state list",\n            self.entity_id,\n            old_len - len(self._state_list),\n        )\n\n    def _handle_invalid_source_state(self, state: State | None) -> bool:\n        # Check the source state for unknown/unavailable condition. If unusable, write unknown/unavailable state and return false.\n        if not state or state.state == STATE_UNAVAILABLE:\n            self._attr_available = False\n            self.async_write_ha_state()\n            return False\n        if not _is_decimal_state(state.state):\n            self._attr_available = True\n            self._write_native_value(None)\n            return False\n        self._attr_available = True\n        return True\n\n    def _write_native_value(self, derivative: Decimal | None) -> None:\n        self._attr_native_value = (\n            None if derivative is None else round(derivative, self._round_digits)\n        )\n        self.async_write_ha_state()\n\n    async def async_added_to_hass(self) -> None:\n        """Handle entity which will be added."""\n        await super().async_added_to_hass()\n        restored_data = await self.async_get_last_sensor_data()\n        if restored_data:\n            self._attr_native_unit_of_measurement = (\n                restored_data.native_unit_of_measurement\n            )\n            try:\n                self._attr_native_value = round(\n                    Decimal(restored_data.native_value),  # type: ignore[arg-type]\n                    self._round_digits,\n                )\n            except (InvalidOperation, TypeError):\n                self._attr_native_value = None\n\n        def schedule_max_sub_interval_exceeded(source_state: State | None) -> None:\n            """Schedule calculation using the source state and max_sub_interval.\n\n            The callback reference is stored for possible cancellation if the source state\n            reports a change before max_sub_interval has passed.\n            If the callback is executed, meaning there was no state change reported, the\n            source_state is assumed constant and calculation is done using its value.\n            """\n            if (\n                self._max_sub_interval is not None\n                and source_state is not None\n                and (_is_decimal_state(source_state.state))\n            ):\n\n                @callback\n                def _calc_derivative_on_max_sub_interval_exceeded_callback(\n                    now: datetime,\n                ) -> None:\n                    """Calculate derivative based on time and reschedule."""\n\n                    _LOGGER.debug(\n                        "%s: Recalculating derivative due to max_sub_interval time elapsed",\n                        self.entity_id,\n                    )\n                    self._prune_state_list(now)\n                    derivative = self._calc_derivative_from_state_list(now)\n                    self._write_native_value(derivative)\n\n                    # If derivative is now zero, don\'t schedule another timeout callback, as it will have no effect\n                    if derivative != 0:\n                        schedule_max_sub_interval_exceeded(source_state)\n\n                _LOGGER.debug(\n                    "%s: Scheduling max_sub_interval_callback in %s",\n                    self.entity_id,\n                    self._max_sub_interval,\n                )\n                self._cancel_max_sub_interval_exceeded_callback = async_call_later(\n                    self.hass,\n                    self._max_sub_interval,\n                    _calc_derivative_on_max_sub_interval_exceeded_callback,\n                )\n\n        @callback\n        def on_state_reported(event: Event[EventStateReportedData]) -> None:\n            """Handle constant sensor state."""\n            _LOGGER.debug(\n                "%s: New state reported event: %s", self.entity_id, event.data\n            )\n            self._cancel_max_sub_interval_exceeded_callback()\n            new_state = event.data["new_state"]\n            if not self._handle_invalid_source_state(new_state):\n                return\n\n            assert new_state\n            if self._attr_native_value == Decimal(0):\n                # If the derivative is zero, and the source sensor hasn\'t\n                # changed state, then we know it will still be zero.\n                return\n            schedule_max_sub_interval_exceeded(new_state)\n            calc_derivative(\n                new_state,\n                new_state.state,\n                event.data["last_reported"],\n                event.data["old_last_reported"],\n            )\n\n        @callback\n        def on_state_changed(event: Event[EventStateChangedData]) -> None:\n            """Handle changed sensor state."""\n            _LOGGER.debug("%s: New state changed event: %s", self.entity_id, event.data)\n            self._cancel_max_sub_interval_exceeded_callback()\n            new_state = event.data["new_state"]\n            if not self._handle_invalid_source_state(new_state):\n                return\n\n            assert new_state\n            schedule_max_sub_interval_exceeded(new_state)\n            old_state = event.data["old_state"]\n            if old_state is not None:\n                calc_derivative(\n                    new_state,\n                    old_state.state,\n                    new_state.last_updated,\n                    old_state.last_reported,\n                )\n            else:\n                # On first state change from none, update availability\n                self.async_write_ha_state()\n\n        def calc_derivative(\n            new_state: State,\n            old_value: str,\n            new_timestamp: datetime,\n            old_timestamp: datetime,\n        ) -> None:\n            """Handle the sensor state changes."""\n            if not _is_decimal_state(old_value):\n                if self._last_valid_state_time:\n                    old_value = self._last_valid_state_time[0]\n                    old_timestamp = self._last_valid_state_time[1]\n                else:\n                    # Sensor becomes valid for the first time, just keep the restored value\n                    self.async_write_ha_state()\n                    return\n\n            if self.native_unit_of_measurement is None:\n                unit = new_state.attributes.get(ATTR_UNIT_OF_MEASUREMENT)\n                self._attr_native_unit_of_measurement = self._unit_template.format(\n                    "" if unit is None else unit\n                )\n\n            self._prune_state_list(new_timestamp)\n\n            try:\n                elapsed_time = (new_timestamp - old_timestamp).total_seconds()\n                delta_value = Decimal(new_state.state) - Decimal(old_value)\n                new_derivative = (\n                    delta_value\n                    / Decimal(elapsed_time)\n                    / Decimal(self._unit_prefix)\n                    * Decimal(self._unit_time)\n                )\n                _LOGGER.debug(\n                    "%s: Calculated new derivative segment as %f / %f / %f * %f = %f",\n                    self.entity_id,\n                    delta_value,\n                    elapsed_time,\n                    self._unit_prefix,\n                    self._unit_time,\n                    new_derivative,\n                )\n\n            except ValueError as err:\n                _LOGGER.warning(\n                    "%s: While calculating derivative: %s", self.entity_id, err\n                )\n            except DecimalException as err:\n                _LOGGER.warning(\n                    "%s: Invalid state (%s > %s): %s",\n                    self.entity_id,\n                    old_value,\n                    new_state.state,\n                    err,\n                )\n            except AssertionError as err:\n                _LOGGER.error(\n                    "%s: Could not calculate derivative: %s", self.entity_id, err\n                )\n\n            # For total inreasing sensors, the value is expected to continuously increase.\n            # A negative derivative for a total increasing sensor likely indicates the\n            # sensor has been reset. To prevent inaccurate data, discard this sample.\n            if (\n                new_state.attributes.get(ATTR_STATE_CLASS)\n                == SensorStateClass.TOTAL_INCREASING\n                and new_derivative < 0\n            ):\n                _LOGGER.debug(\n                    "%s: Dropping sample as source total_increasing sensor decreased",\n                    self.entity_id,\n                )\n                return\n\n            # add latest derivative to the window list\n            self._state_list.append((old_timestamp, new_timestamp, new_derivative))\n            self._last_valid_state_time = (\n                new_state.state,\n                new_timestamp,\n            )\n\n            # If outside of time window just report derivative (is the same as modeling it in the window),\n            # otherwise take the weighted average with the previous derivatives\n            if elapsed_time > self._time_window:\n                derivative = new_derivative\n            else:\n                derivative = self._calc_derivative_from_state_list(new_timestamp)\n            self._write_native_value(derivative)\n\n        source_state = self.hass.states.get(self._sensor_source_id)\n        if source_state is None or source_state.state in [\n            STATE_UNAVAILABLE,\n            STATE_UNKNOWN,\n        ]:\n            self._attr_available = False\n\n        if self._max_sub_interval is not None:\n            schedule_max_sub_interval_exceeded(source_state)\n\n            @callback\n            def on_removed() -> None:\n                self._cancel_max_sub_interval_exceeded_callback()\n\n            self.async_on_remove(on_removed)\n\n        self.async_on_remove(\n            async_track_state_change_event(\n                self.hass, self._sensor_source_id, on_state_changed\n            )\n        )\n\n        self.async_on_remove(\n            async_track_state_report_event(\n                self.hass, self._sensor_source_id, on_state_reported\n            )\n        )\n',
            'tests/components/derivative/test_config_flow.py': '"""Test the Derivative config flow."""\n\nfrom datetime import timedelta\nfrom unittest.mock import patch\n\nfrom freezegun import freeze_time\nimport pytest\n\nfrom homeassistant import config_entries\nfrom homeassistant.components.derivative.const import DOMAIN\nfrom homeassistant.const import STATE_UNAVAILABLE\nfrom homeassistant.core import HomeAssistant\nfrom homeassistant.data_entry_flow import FlowResultType\nfrom homeassistant.helpers import selector\nfrom homeassistant.util import dt as dt_util\n\nfrom tests.common import MockConfigEntry, get_schema_suggested_value\n\n\n@pytest.mark.parametrize("platform", ["sensor"])\nasync def test_config_flow(hass: HomeAssistant, platform) -> None:\n    """Test the config flow."""\n    input_sensor_entity_id = "sensor.input"\n\n    result = await hass.config_entries.flow.async_init(\n        DOMAIN, context={"source": config_entries.SOURCE_USER}\n    )\n    assert result["type"] is FlowResultType.FORM\n    assert result["errors"] is None\n\n    with patch(\n        "homeassistant.components.derivative.async_setup_entry",\n        return_value=True,\n    ) as mock_setup_entry:\n        result = await hass.config_entries.flow.async_configure(\n            result["flow_id"],\n            {\n                "name": "My derivative",\n                "round": 1,\n                "source": input_sensor_entity_id,\n                "time_window": {"seconds": 0},\n                "unit_time": "min",\n                "max_sub_interval": {"minutes": 1},\n            },\n        )\n        await hass.async_block_till_done()\n\n    assert result["type"] is FlowResultType.CREATE_ENTRY\n    assert result["title"] == "My derivative"\n    assert result["data"] == {}\n    assert result["options"] == {\n        "name": "My derivative",\n        "round": 1.0,\n        "source": "sensor.input",\n        "time_window": {"seconds": 0.0},\n        "unit_time": "min",\n        "max_sub_interval": {"minutes": 1.0},\n    }\n    assert len(mock_setup_entry.mock_calls) == 1\n\n    config_entry = hass.config_entries.async_entries(DOMAIN)[0]\n    assert config_entry.data == {}\n    assert config_entry.options == {\n        "name": "My derivative",\n        "round": 1.0,\n        "source": "sensor.input",\n        "time_window": {"seconds": 0.0},\n        "unit_time": "min",\n        "max_sub_interval": {"minutes": 1.0},\n    }\n    assert config_entry.title == "My derivative"\n\n\n@pytest.mark.parametrize("platform", ["sensor"])\n@pytest.mark.parametrize(\n    ("unit_prefix_entry", "unit_prefix_used"),\n    [("k", "k"), ("\\u00b5", "\\u03bc"), ("\\u03bc", "\\u03bc")],\n)\nasync def test_options(\n    hass: HomeAssistant, platform, unit_prefix_entry: str, unit_prefix_used: str\n) -> None:\n    """Test reconfiguring and migrated unit prefix."""\n    # Setup the config entry\n    config_entry = MockConfigEntry(\n        data={},\n        domain=DOMAIN,\n        options={\n            "name": "My derivative",\n            "round": 1.0,\n            "source": "sensor.input",\n            "time_window": {"seconds": 0.0},\n            "unit_prefix": unit_prefix_entry,\n            "unit_time": "min",\n            "max_sub_interval": {"seconds": 30},\n        },\n        title="My derivative",\n    )\n    config_entry.add_to_hass(hass)\n    assert await hass.config_entries.async_setup(config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    hass.states.async_set("sensor.input", 10, {"unit_of_measurement": "dog"})\n    hass.states.async_set("sensor.valid", 10, {"unit_of_measurement": "dog"})\n    hass.states.async_set("sensor.invalid", 10, {"unit_of_measurement": "cat"})\n\n    result = await hass.config_entries.options.async_init(config_entry.entry_id)\n    assert result["type"] is FlowResultType.FORM\n    assert result["step_id"] == "init"\n    schema = result["data_schema"].schema\n    assert get_schema_suggested_value(schema, "round") == 1.0\n    assert get_schema_suggested_value(schema, "time_window") == {"seconds": 0.0}\n    assert get_schema_suggested_value(schema, "unit_prefix") == unit_prefix_used\n    assert get_schema_suggested_value(schema, "unit_time") == "min"\n\n    source = schema["source"]\n    assert isinstance(source, selector.EntitySelector)\n    assert source.config["include_entities"] == [\n        "sensor.input",\n        "sensor.valid",\n    ]\n\n    result = await hass.config_entries.options.async_configure(\n        result["flow_id"],\n        user_input={\n            "source": "sensor.valid",\n            "round": 2.0,\n            "time_window": {"seconds": 10.0},\n            "unit_time": "h",\n        },\n    )\n    assert result["type"] is FlowResultType.CREATE_ENTRY\n    assert result["data"] == {\n        "name": "My derivative",\n        "round": 2.0,\n        "source": "sensor.valid",\n        "time_window": {"seconds": 10.0},\n        "unit_time": "h",\n    }\n    assert config_entry.data == {}\n    assert config_entry.options == {\n        "name": "My derivative",\n        "round": 2.0,\n        "source": "sensor.valid",\n        "time_window": {"seconds": 10.0},\n        "unit_time": "h",\n    }\n    assert config_entry.title == "My derivative"\n\n    # Check config entry is reloaded with new options\n    await hass.async_block_till_done()\n\n    # Check the entity was updated, no new entity was created\n    assert len(hass.states.async_all()) == 4\n\n    # Check the state of the entity has changed as expected\n    hass.states.async_set("sensor.valid", 10, {"unit_of_measurement": "cat"})\n    hass.states.async_set("sensor.valid", 11, {"unit_of_measurement": "cat"})\n    await hass.async_block_till_done()\n    state = hass.states.get(f"{platform}.my_derivative")\n    assert state.attributes["unit_of_measurement"] == "cat/h"\n\n\nasync def test_update_unit(hass: HomeAssistant) -> None:\n    """Test behavior of changing the unit_time option."""\n    # Setup the config entry\n    source_id = "sensor.source"\n    config_entry = MockConfigEntry(\n        data={},\n        domain=DOMAIN,\n        options={\n            "name": "My derivative",\n            "round": 1.0,\n            "source": source_id,\n            "unit_time": "min",\n            "time_window": {"seconds": 0.0},\n        },\n        title="My derivative",\n    )\n    derivative_id = "sensor.my_derivative"\n    config_entry.add_to_hass(hass)\n    assert await hass.config_entries.async_setup(config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    state = hass.states.get(derivative_id)\n    assert state.state == STATE_UNAVAILABLE\n    assert state.attributes.get("unit_of_measurement") is None\n\n    time = dt_util.utcnow()\n    with freeze_time(time) as freezer:\n        # First state update of the source.\n        # Derivative does not learn the unit yet.\n        hass.states.async_set(source_id, 5, {"unit_of_measurement": "dogs"})\n        await hass.async_block_till_done()\n        state = hass.states.get(derivative_id)\n        assert state.state == "0.0"\n        assert state.attributes.get("unit_of_measurement") is None\n\n        # Second state update of the source.\n        time += timedelta(minutes=1)\n        freezer.move_to(time)\n        hass.states.async_set(source_id, "7", {"unit_of_measurement": "dogs"})\n        await hass.async_block_till_done()\n        state = hass.states.get(derivative_id)\n        assert state.state == "2.0"\n        assert state.attributes.get("unit_of_measurement") == "dogs/min"\n\n        # Update the unit_time from minutes to seconds.\n        result = await hass.config_entries.options.async_init(config_entry.entry_id)\n        result = await hass.config_entries.options.async_configure(\n            result["flow_id"],\n            user_input={\n                "source": source_id,\n                "round": 1.0,\n                "unit_time": "s",\n                "time_window": {"seconds": 0.0},\n            },\n        )\n        await hass.async_block_till_done()\n\n        # Check the state after reconfigure. Neither unit or state has changed.\n        state = hass.states.get(derivative_id)\n        assert state.state == "2.0"\n        assert state.attributes.get("unit_of_measurement") == "dogs/min"\n\n        # Third state update of the source.\n        time += timedelta(seconds=1)\n        freezer.move_to(time)\n        hass.states.async_set(source_id, "10", {"unit_of_measurement": "dogs"})\n        await hass.async_block_till_done()\n        state = hass.states.get(derivative_id)\n        assert state.state == "3.0"\n        # While the state is correctly reporting a state of 3 dogs per second, it incorrectly keeps\n        # the unit as dogs/min\n        assert state.attributes.get("unit_of_measurement") == "dogs/min"\n\n        # Fourth state update of the source.\n        time += timedelta(seconds=1)\n        freezer.move_to(time)\n        hass.states.async_set(source_id, "20", {"unit_of_measurement": "dogs"})\n        await hass.async_block_till_done()\n        state = hass.states.get(derivative_id)\n        assert state.state == "10.0"\n        assert state.attributes.get("unit_of_measurement") == "dogs/min"\n',
            'tests/components/derivative/test_init.py': '"""Test the Derivative integration."""\n\nfrom unittest.mock import patch\n\nimport pytest\n\nfrom homeassistant.components import derivative\nfrom homeassistant.components.derivative.const import DOMAIN\nfrom homeassistant.config_entries import ConfigEntry, ConfigEntryState\nfrom homeassistant.core import Event, HomeAssistant, callback\nfrom homeassistant.helpers import device_registry as dr, entity_registry as er\nfrom homeassistant.helpers.event import async_track_entity_registry_updated_event\n\nfrom tests.common import MockConfigEntry\n\n\ndef track_entity_registry_actions(hass: HomeAssistant, entity_id: str) -> list[str]:\n    """Track entity registry actions for an entity."""\n    events = []\n\n    @callback\n    def add_event(event: Event[er.EventEntityRegistryUpdatedData]) -> None:\n        """Add entity registry updated event to the list."""\n        events.append(event.data["action"])\n\n    async_track_entity_registry_updated_event(hass, entity_id, add_event)\n\n    return events\n\n\nasync def test_setup_and_remove_config_entry(\n    hass: HomeAssistant,\n    entity_registry: er.EntityRegistry,\n) -> None:\n    """Test setting up and removing a config entry."""\n    input_sensor_entity_id = "sensor.input"\n    derivative_entity_id = "sensor.my_derivative"\n\n    hass.states.async_set(input_sensor_entity_id, "10.0", {})\n    await hass.async_block_till_done()\n\n    # Setup the config entry\n    config_entry = MockConfigEntry(\n        data={},\n        domain=DOMAIN,\n        options={\n            "name": "My derivative",\n            "round": 1.0,\n            "source": "sensor.input",\n            "time_window": {"seconds": 0.0},\n            "unit_prefix": "k",\n            "unit_time": "min",\n        },\n        title="My derivative",\n    )\n    config_entry.add_to_hass(hass)\n    assert await hass.config_entries.async_setup(config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    # Check the entity is registered in the entity registry\n    assert entity_registry.async_get(derivative_entity_id) is not None\n\n    # Check the platform is setup correctly\n    state = hass.states.get(derivative_entity_id)\n    assert state.state == "0.0"\n    assert "unit_of_measurement" not in state.attributes\n    assert state.attributes["source"] == "sensor.input"\n\n    hass.states.async_set(input_sensor_entity_id, 10, {"unit_of_measurement": "dog"})\n    hass.states.async_set(input_sensor_entity_id, 11, {"unit_of_measurement": "dog"})\n    await hass.async_block_till_done()\n    state = hass.states.get(derivative_entity_id)\n    assert state.state != "0"\n    assert state.attributes["unit_of_measurement"] == "kdog/min"\n\n    # Remove the config entry\n    assert await hass.config_entries.async_remove(config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    # Check the state and entity registry entry are removed\n    assert hass.states.get(derivative_entity_id) is None\n    assert entity_registry.async_get(derivative_entity_id) is None\n\n\nasync def test_device_cleaning(\n    hass: HomeAssistant,\n    device_registry: dr.DeviceRegistry,\n    entity_registry: er.EntityRegistry,\n) -> None:\n    """Test for source entity device for Derivative."""\n\n    # Source entity device config entry\n    source_config_entry = MockConfigEntry()\n    source_config_entry.add_to_hass(hass)\n\n    # Device entry of the source entity\n    source_device1_entry = device_registry.async_get_or_create(\n        config_entry_id=source_config_entry.entry_id,\n        identifiers={("sensor", "identifier_test1")},\n        connections={("mac", "30:31:32:33:34:01")},\n    )\n\n    # Source entity registry\n    source_entity = entity_registry.async_get_or_create(\n        "sensor",\n        "test",\n        "source",\n        config_entry=source_config_entry,\n        device_id=source_device1_entry.id,\n    )\n    await hass.async_block_till_done()\n    assert entity_registry.async_get("sensor.test_source") is not None\n\n    # Configure the configuration entry for Derivative\n    derivative_config_entry = MockConfigEntry(\n        data={},\n        domain=DOMAIN,\n        options={\n            "name": "Derivative",\n            "round": 1.0,\n            "source": "sensor.test_source",\n            "time_window": {"seconds": 0.0},\n            "unit_prefix": "k",\n            "unit_time": "min",\n        },\n        title="Derivative",\n    )\n    derivative_config_entry.add_to_hass(hass)\n    assert await hass.config_entries.async_setup(derivative_config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    # Confirm the link between the source entity device and the derivative sensor\n    derivative_entity = entity_registry.async_get("sensor.derivative")\n    assert derivative_entity is not None\n    assert derivative_entity.device_id == source_entity.device_id\n\n    # Device entry incorrectly linked to Derivative config entry\n    device_registry.async_get_or_create(\n        config_entry_id=derivative_config_entry.entry_id,\n        identifiers={("sensor", "identifier_test2")},\n        connections={("mac", "30:31:32:33:34:02")},\n    )\n    device_registry.async_get_or_create(\n        config_entry_id=derivative_config_entry.entry_id,\n        identifiers={("sensor", "identifier_test3")},\n        connections={("mac", "30:31:32:33:34:03")},\n    )\n    await hass.async_block_till_done()\n\n    # Before reloading the config entry, two devices are expected to be linked\n    devices_before_reload = device_registry.devices.get_devices_for_config_entry_id(\n        derivative_config_entry.entry_id\n    )\n    assert len(devices_before_reload) == 2\n\n    # Config entry reload\n    await hass.config_entries.async_reload(derivative_config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    # Confirm the link between the source entity device and the derivative sensor after reload\n    derivative_entity = entity_registry.async_get("sensor.derivative")\n    assert derivative_entity is not None\n    assert derivative_entity.device_id == source_entity.device_id\n\n    # After reloading the config entry, only one linked device is expected\n    devices_after_reload = device_registry.devices.get_devices_for_config_entry_id(\n        derivative_config_entry.entry_id\n    )\n    assert len(devices_after_reload) == 0\n\n\nasync def test_async_handle_source_entity_changes_source_entity_removed(\n    hass: HomeAssistant,\n    device_registry: dr.DeviceRegistry,\n    entity_registry: er.EntityRegistry,\n    derivative_config_entry: MockConfigEntry,\n    sensor_config_entry: ConfigEntry,\n    sensor_device: dr.DeviceEntry,\n    sensor_entity_entry: er.RegistryEntry,\n) -> None:\n    """Test the derivative config entry is removed when the source entity is removed."""\n    assert await hass.config_entries.async_setup(derivative_config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    derivative_entity_entry = entity_registry.async_get("sensor.my_derivative")\n    assert derivative_entity_entry.device_id == sensor_entity_entry.device_id\n\n    sensor_device = device_registry.async_get(sensor_device.id)\n    assert derivative_config_entry.entry_id not in sensor_device.config_entries\n\n    events = track_entity_registry_actions(hass, derivative_entity_entry.entity_id)\n\n    # Remove the source sensor\'s config entry from the device, this removes the\n    # source sensor\n    with patch(\n        "homeassistant.components.derivative.async_unload_entry",\n        wraps=derivative.async_unload_entry,\n    ) as mock_unload_entry:\n        device_registry.async_update_device(\n            sensor_device.id, remove_config_entry_id=sensor_config_entry.entry_id\n        )\n        await hass.async_block_till_done()\n        await hass.async_block_till_done()\n    mock_unload_entry.assert_not_called()\n\n    # Check that the entity is no longer linked to the source device\n    derivative_entity_entry = entity_registry.async_get("sensor.my_derivative")\n    assert derivative_entity_entry.device_id is None\n\n    # Check that the device is removed\n    assert not device_registry.async_get(sensor_device.id)\n\n    # Check that the derivative config entry is not removed\n    assert derivative_config_entry.entry_id in hass.config_entries.async_entry_ids()\n\n    # Check we got the expected events\n    assert events == ["update"]\n\n\nasync def test_async_handle_source_entity_changes_source_entity_removed_shared_device(\n    hass: HomeAssistant,\n    device_registry: dr.DeviceRegistry,\n    entity_registry: er.EntityRegistry,\n    derivative_config_entry: MockConfigEntry,\n    sensor_config_entry: ConfigEntry,\n    sensor_device: dr.DeviceEntry,\n    sensor_entity_entry: er.RegistryEntry,\n) -> None:\n    """Test the derivative config entry is removed when the source entity is removed."""\n    # Add another config entry to the sensor device\n    other_config_entry = MockConfigEntry()\n    other_config_entry.add_to_hass(hass)\n    device_registry.async_update_device(\n        sensor_device.id, add_config_entry_id=other_config_entry.entry_id\n    )\n\n    assert await hass.config_entries.async_setup(derivative_config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    derivative_entity_entry = entity_registry.async_get("sensor.my_derivative")\n    assert derivative_entity_entry.device_id == sensor_entity_entry.device_id\n\n    sensor_device = device_registry.async_get(sensor_device.id)\n    assert derivative_config_entry.entry_id not in sensor_device.config_entries\n\n    events = track_entity_registry_actions(hass, derivative_entity_entry.entity_id)\n\n    # Remove the source sensor\'s config entry from the device, this removes the\n    # source sensor\n    with patch(\n        "homeassistant.components.derivative.async_unload_entry",\n        wraps=derivative.async_unload_entry,\n    ) as mock_unload_entry:\n        device_registry.async_update_device(\n            sensor_device.id, remove_config_entry_id=sensor_config_entry.entry_id\n        )\n        await hass.async_block_till_done()\n        await hass.async_block_till_done()\n    mock_unload_entry.assert_not_called()\n\n    # Check that the entity is no longer linked to the source device\n    derivative_entity_entry = entity_registry.async_get("sensor.my_derivative")\n    assert derivative_entity_entry.device_id is None\n\n    # Check that the derivative config entry is not in the device\n    sensor_device = device_registry.async_get(sensor_device.id)\n    assert derivative_config_entry.entry_id not in sensor_device.config_entries\n\n    # Check that the derivative config entry is not removed\n    assert derivative_config_entry.entry_id in hass.config_entries.async_entry_ids()\n\n    # Check we got the expected events\n    assert events == ["update"]\n\n\nasync def test_async_handle_source_entity_changes_source_entity_removed_from_device(\n    hass: HomeAssistant,\n    device_registry: dr.DeviceRegistry,\n    entity_registry: er.EntityRegistry,\n    derivative_config_entry: MockConfigEntry,\n    sensor_device: dr.DeviceEntry,\n    sensor_entity_entry: er.RegistryEntry,\n) -> None:\n    """Test the source entity removed from the source device."""\n    assert await hass.config_entries.async_setup(derivative_config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    derivative_entity_entry = entity_registry.async_get("sensor.my_derivative")\n    assert derivative_entity_entry.device_id == sensor_entity_entry.device_id\n\n    sensor_device = device_registry.async_get(sensor_device.id)\n    assert derivative_config_entry.entry_id not in sensor_device.config_entries\n\n    events = track_entity_registry_actions(hass, derivative_entity_entry.entity_id)\n\n    # Remove the source sensor from the device\n    with patch(\n        "homeassistant.components.derivative.async_unload_entry",\n        wraps=derivative.async_unload_entry,\n    ) as mock_unload_entry:\n        entity_registry.async_update_entity(\n            sensor_entity_entry.entity_id, device_id=None\n        )\n        await hass.async_block_till_done()\n    mock_unload_entry.assert_called_once()\n\n    # Check that the entity is no longer linked to the source device\n    derivative_entity_entry = entity_registry.async_get("sensor.my_derivative")\n    assert derivative_entity_entry.device_id is None\n\n    # Check that the derivative config entry is not in the device\n    sensor_device = device_registry.async_get(sensor_device.id)\n    assert derivative_config_entry.entry_id not in sensor_device.config_entries\n\n    # Check that the derivative config entry is not removed\n    assert derivative_config_entry.entry_id in hass.config_entries.async_entry_ids()\n\n    # Check we got the expected events\n    assert events == ["update"]\n\n\nasync def test_async_handle_source_entity_changes_source_entity_moved_other_device(\n    hass: HomeAssistant,\n    device_registry: dr.DeviceRegistry,\n    entity_registry: er.EntityRegistry,\n    derivative_config_entry: MockConfigEntry,\n    sensor_config_entry: ConfigEntry,\n    sensor_device: dr.DeviceEntry,\n    sensor_entity_entry: er.RegistryEntry,\n) -> None:\n    """Test the source entity is moved to another device."""\n    sensor_device_2 = device_registry.async_get_or_create(\n        config_entry_id=sensor_config_entry.entry_id,\n        connections={(dr.CONNECTION_NETWORK_MAC, "12:34:56:AB:CD:FF")},\n    )\n\n    assert await hass.config_entries.async_setup(derivative_config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    derivative_entity_entry = entity_registry.async_get("sensor.my_derivative")\n    assert derivative_entity_entry.device_id == sensor_entity_entry.device_id\n\n    sensor_device = device_registry.async_get(sensor_device.id)\n    assert derivative_config_entry.entry_id not in sensor_device.config_entries\n    sensor_device_2 = device_registry.async_get(sensor_device_2.id)\n    assert derivative_config_entry.entry_id not in sensor_device_2.config_entries\n\n    events = track_entity_registry_actions(hass, derivative_entity_entry.entity_id)\n\n    # Move the source sensor to another device\n    with patch(\n        "homeassistant.components.derivative.async_unload_entry",\n        wraps=derivative.async_unload_entry,\n    ) as mock_unload_entry:\n        entity_registry.async_update_entity(\n            sensor_entity_entry.entity_id, device_id=sensor_device_2.id\n        )\n        await hass.async_block_till_done()\n    mock_unload_entry.assert_called_once()\n\n    # Check that the entity is linked to the other device\n    derivative_entity_entry = entity_registry.async_get("sensor.my_derivative")\n    assert derivative_entity_entry.device_id == sensor_device_2.id\n\n    # Check that the derivative config entry is not in any of the devices\n    sensor_device = device_registry.async_get(sensor_device.id)\n    assert derivative_config_entry.entry_id not in sensor_device.config_entries\n    sensor_device_2 = device_registry.async_get(sensor_device_2.id)\n    assert derivative_config_entry.entry_id not in sensor_device_2.config_entries\n\n    # Check that the derivative config entry is not removed\n    assert derivative_config_entry.entry_id in hass.config_entries.async_entry_ids()\n\n    # Check we got the expected events\n    assert events == ["update"]\n\n\nasync def test_async_handle_source_entity_new_entity_id(\n    hass: HomeAssistant,\n    device_registry: dr.DeviceRegistry,\n    entity_registry: er.EntityRegistry,\n    derivative_config_entry: MockConfigEntry,\n    sensor_device: dr.DeviceEntry,\n    sensor_entity_entry: er.RegistryEntry,\n) -> None:\n    """Test the source entity\'s entity ID is changed."""\n    assert await hass.config_entries.async_setup(derivative_config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    derivative_entity_entry = entity_registry.async_get("sensor.my_derivative")\n    assert derivative_entity_entry.device_id == sensor_entity_entry.device_id\n\n    sensor_device = device_registry.async_get(sensor_device.id)\n    assert derivative_config_entry.entry_id not in sensor_device.config_entries\n\n    events = track_entity_registry_actions(hass, derivative_entity_entry.entity_id)\n\n    # Change the source entity\'s entity ID\n    with patch(\n        "homeassistant.components.derivative.async_unload_entry",\n        wraps=derivative.async_unload_entry,\n    ) as mock_unload_entry:\n        entity_registry.async_update_entity(\n            sensor_entity_entry.entity_id, new_entity_id="sensor.new_entity_id"\n        )\n        await hass.async_block_till_done()\n    mock_unload_entry.assert_called_once()\n\n    # Check that the derivative config entry is updated with the new entity ID\n    assert derivative_config_entry.options["source"] == "sensor.new_entity_id"\n\n    # Check that the helper config is not in the device\n    sensor_device = device_registry.async_get(sensor_device.id)\n    assert derivative_config_entry.entry_id not in sensor_device.config_entries\n\n    # Check that the derivative config entry is not removed\n    assert derivative_config_entry.entry_id in hass.config_entries.async_entry_ids()\n\n    # Check we got the expected events\n    assert events == []\n\n\n@pytest.mark.parametrize(\n    ("unit_prefix", "expect_prefix"),\n    [\n        ({}, None),\n        ({"unit_prefix": "k"}, "k"),\n        ({"unit_prefix": "none"}, None),\n    ],\n)\nasync def test_migration_1_1(hass: HomeAssistant, unit_prefix, expect_prefix) -> None:\n    """Test migration from v1.1 deletes "none" unit_prefix."""\n\n    config_entry = MockConfigEntry(\n        data={},\n        domain=DOMAIN,\n        options={\n            "name": "My derivative",\n            "round": 1.0,\n            "source": "sensor.power",\n            "time_window": {"seconds": 0.0},\n            **unit_prefix,\n            "unit_time": "min",\n        },\n        title="My derivative",\n        version=1,\n        minor_version=1,\n    )\n    config_entry.add_to_hass(hass)\n    await hass.config_entries.async_setup(config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    assert config_entry.state is ConfigEntryState.LOADED\n    assert config_entry.options["unit_time"] == "min"\n    assert config_entry.options.get("unit_prefix") == expect_prefix\n\n    assert config_entry.version == 1\n    assert config_entry.minor_version == 4\n\n\nasync def test_migration_1_2(\n    hass: HomeAssistant,\n    device_registry: dr.DeviceRegistry,\n    entity_registry: er.EntityRegistry,\n    sensor_device: dr.DeviceEntry,\n    sensor_entity_entry: er.RegistryEntry,\n) -> None:\n    """Test migration from v1.2 removes derivative config entry from device."""\n\n    derivative_config_entry = MockConfigEntry(\n        data={},\n        domain=DOMAIN,\n        options={\n            "name": "My derivative",\n            "round": 1.0,\n            "source": "sensor.test_unique",\n            "time_window": {"seconds": 0.0},\n            "unit_prefix": "k",\n            "unit_time": "min",\n        },\n        title="My derivative",\n        version=1,\n        minor_version=2,\n    )\n    derivative_config_entry.add_to_hass(hass)\n\n    # Add the helper config entry to the device\n    device_registry.async_update_device(\n        sensor_device.id, add_config_entry_id=derivative_config_entry.entry_id\n    )\n\n    # Check preconditions\n    sensor_device = device_registry.async_get(sensor_device.id)\n    assert derivative_config_entry.entry_id in sensor_device.config_entries\n\n    await hass.config_entries.async_setup(derivative_config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    assert derivative_config_entry.state is ConfigEntryState.LOADED\n\n    # Check that the helper config entry is removed from the device and the helper\n    # entity is linked to the source device\n    sensor_device = device_registry.async_get(sensor_device.id)\n    assert derivative_config_entry.entry_id not in sensor_device.config_entries\n    derivative_entity_entry = entity_registry.async_get("sensor.my_derivative")\n    assert derivative_entity_entry.device_id == sensor_entity_entry.device_id\n\n    assert derivative_config_entry.version == 1\n    assert derivative_config_entry.minor_version == 4\n\n\n@pytest.mark.parametrize(\n    ("unit_prefix", "expect_prefix"),\n    [\n        ({"unit_prefix": "\\u00b5"}, "\\u03bc"),\n        ({"unit_prefix": "\\u03bc"}, "\\u03bc"),\n    ],\n)\nasync def test_migration_1_4(hass: HomeAssistant, unit_prefix, expect_prefix) -> None:\n    """Test migration from v1.4 migrates to Greek Mu char" unit_prefix."""\n\n    config_entry = MockConfigEntry(\n        data={},\n        domain=DOMAIN,\n        options={\n            "name": "My derivative",\n            "round": 1.0,\n            "source": "sensor.power",\n            "time_window": {"seconds": 0.0},\n            **unit_prefix,\n            "unit_time": "min",\n        },\n        title="My derivative",\n        version=1,\n        minor_version=1,\n    )\n    config_entry.add_to_hass(hass)\n    await hass.config_entries.async_setup(config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    assert config_entry.state is ConfigEntryState.LOADED\n    assert config_entry.options["unit_time"] == "min"\n    assert config_entry.options.get("unit_prefix") == expect_prefix\n\n    assert config_entry.version == 1\n    assert config_entry.minor_version == 4\n\n\nasync def test_migration_from_future_version(\n    hass: HomeAssistant,\n) -> None:\n    """Test migration from future version."""\n\n    config_entry = MockConfigEntry(\n        data={},\n        domain=DOMAIN,\n        options={\n            "name": "My derivative",\n            "round": 1.0,\n            "source": "sensor.power",\n            "time_window": {"seconds": 0.0},\n            "unit_prefix": "k",\n            "unit_time": "min",\n        },\n        title="My derivative",\n        version=2,\n        minor_version=1,\n    )\n    config_entry.add_to_hass(hass)\n    await hass.config_entries.async_setup(config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    assert config_entry.state is ConfigEntryState.MIGRATION_ERROR\n',
            'tests/components/derivative/test_sensor.py': '"""The tests for the derivative sensor platform."""\n\nfrom datetime import timedelta\nfrom math import sin\nimport random\nfrom typing import Any\n\nfrom freezegun import freeze_time\nimport pytest\n\nfrom homeassistant.components.derivative.const import DOMAIN\nfrom homeassistant.components.sensor import ATTR_STATE_CLASS, SensorStateClass\nfrom homeassistant.const import (\n    STATE_UNAVAILABLE,\n    STATE_UNKNOWN,\n    UnitOfPower,\n    UnitOfTime,\n)\nfrom homeassistant.core import (\n    Event,\n    EventStateChangedData,\n    HomeAssistant,\n    State,\n    callback,\n)\nfrom homeassistant.helpers import device_registry as dr, entity_registry as er\nfrom homeassistant.helpers.event import async_track_state_change_event\nfrom homeassistant.setup import async_setup_component\nfrom homeassistant.util import dt as dt_util\n\nfrom tests.common import (\n    MockConfigEntry,\n    async_fire_time_changed,\n    mock_restore_cache_with_extra_data,\n)\n\nA1 = {"attr": "value1"}\nA2 = {"attr": "value2"}\n\n\n@pytest.mark.parametrize("force_update", [False, True])\n@pytest.mark.parametrize(\n    "attributes",\n    [\n        # Same attributes, fires state report\n        [A1, A1],\n        # Changing attributes, fires state change with bumped last_updated\n        [A1, A2],\n    ],\n)\nasync def test_state(\n    hass: HomeAssistant,\n    force_update: bool,\n    attributes: list[dict[str, Any]],\n) -> None:\n    """Test derivative sensor state."""\n    config = {\n        "sensor": {\n            "platform": "derivative",\n            "name": "derivative",\n            "source": "sensor.energy",\n            "unit": "kW",\n            "round": 2,\n        }\n    }\n\n    assert await async_setup_component(hass, "sensor", config)\n\n    entity_id = config["sensor"]["source"]\n    base = dt_util.utcnow()\n    with freeze_time(base) as freezer:\n        for extra_attributes in attributes:\n            hass.states.async_set(\n                entity_id, 1, extra_attributes, force_update=force_update\n            )\n            await hass.async_block_till_done()\n\n            freezer.move_to(dt_util.utcnow() + timedelta(seconds=3600))\n\n    state = hass.states.get("sensor.derivative")\n    assert state is not None\n\n    # Testing a energy sensor at 1 kWh for 1hour = 0kW\n    assert round(float(state.state), config["sensor"]["round"]) == 0.0\n\n    assert state.attributes.get("unit_of_measurement") == "kW"\n\n\n# Test unchanged states work both with and without max_sub_interval\n@pytest.mark.parametrize("extra_config", [{}, {"max_sub_interval": {"minutes": 9999}}])\n@pytest.mark.parametrize("force_update", [False, True])\n@pytest.mark.parametrize(\n    "attributes",\n    [\n        # Same attributes, fires state report\n        [A1, A1, A1, A1],\n        # Changing attributes, fires state change with bumped last_updated\n        [A1, A2, A1, A2],\n    ],\n)\nasync def test_no_change(\n    hass: HomeAssistant,\n    extra_config: dict[str, Any],\n    force_update: bool,\n    attributes: list[dict[str, Any]],\n) -> None:\n    """Test derivative sensor state updated when source sensor doesn\'t change."""\n    events: list[Event[EventStateChangedData]] = []\n\n    @callback\n    def _capture_event(event: Event) -> None:\n        events.append(event)\n\n    async_track_state_change_event(hass, "sensor.derivative", _capture_event)\n\n    config = {\n        "sensor": {\n            "platform": "derivative",\n            "name": "derivative",\n            "source": "sensor.energy",\n            "unit": "kW",\n            "round": 2,\n        }\n        | extra_config\n    }\n\n    assert await async_setup_component(hass, "sensor", config)\n    await hass.async_block_till_done()\n\n    entity_id = config["sensor"]["source"]\n    base = dt_util.utcnow()\n    with freeze_time(base) as freezer:\n        for value, extra_attributes in zip([0, 1, 1, 1], attributes, strict=True):\n            hass.states.async_set(\n                entity_id, value, extra_attributes, force_update=force_update\n            )\n            await hass.async_block_till_done()\n\n            freezer.move_to(dt_util.utcnow() + timedelta(seconds=3600))\n\n    state = hass.states.get("sensor.derivative")\n    assert state is not None\n\n    await hass.async_block_till_done()\n    await hass.async_block_till_done()\n    states = [events[0].data["new_state"].state] + [\n        round(float(event.data["new_state"].state), config["sensor"]["round"])\n        for event in events[1:]\n    ]\n    # Testing a energy sensor at 1 kWh for 1hour = 0kW\n    assert states == ["unavailable", 0.0, 1.0, 0.0]\n\n    state = events[-1].data["new_state"]\n\n    assert state.attributes.get("unit_of_measurement") == "kW"\n\n    assert state.last_changed == base + timedelta(seconds=2 * 3600)\n\n\nasync def _setup_sensor(\n    hass: HomeAssistant, config: dict[str, Any]\n) -> tuple[dict[str, Any], str]:\n    default_config = {\n        "platform": "derivative",\n        "name": "power",\n        "source": "sensor.energy",\n        "round": 2,\n    }\n\n    config = {"sensor": dict(default_config, **config)}\n    assert await async_setup_component(hass, "sensor", config)\n    await hass.async_block_till_done()\n\n    entity_id = config["sensor"]["source"]\n    hass.states.async_set(entity_id, 0, {})\n    await hass.async_block_till_done()\n\n    return config, entity_id\n\n\nasync def setup_tests(\n    hass: HomeAssistant,\n    config: dict[str, Any],\n    times: list[int],\n    values: list[float],\n    expected_state: float,\n) -> State:\n    """Test derivative sensor state."""\n    config, entity_id = await _setup_sensor(hass, config)\n\n    # Testing a energy sensor with non-monotonic intervals and values\n    base = dt_util.utcnow()\n    with freeze_time(base) as freezer:\n        for time, value in zip(times, values, strict=True):\n            freezer.move_to(base + timedelta(seconds=time))\n            hass.states.async_set(entity_id, value, {})\n            await hass.async_block_till_done()\n\n    state = hass.states.get("sensor.power")\n    assert state is not None\n\n    assert round(float(state.state), config["sensor"]["round"]) == expected_state\n\n    return state\n\n\nasync def test_dataSet1(hass: HomeAssistant) -> None:\n    """Test derivative sensor state."""\n    await setup_tests(\n        hass,\n        {"unit_time": UnitOfTime.SECONDS},\n        times=[20, 30, 40, 50],\n        values=[10, 30, 5, 0],\n        expected_state=-0.5,\n    )\n\n\nasync def test_dataSet2(hass: HomeAssistant) -> None:\n    """Test derivative sensor state."""\n    await setup_tests(\n        hass,\n        {"unit_time": UnitOfTime.SECONDS},\n        times=[20, 30],\n        values=[5, 0],\n        expected_state=-0.5,\n    )\n\n\nasync def test_dataSet3(hass: HomeAssistant) -> None:\n    """Test derivative sensor state."""\n    state = await setup_tests(\n        hass,\n        {"unit_time": UnitOfTime.SECONDS},\n        times=[20, 30],\n        values=[5, 10],\n        expected_state=0.5,\n    )\n\n    assert state.attributes.get("unit_of_measurement") == f"/{UnitOfTime.SECONDS}"\n\n\nasync def test_dataSet4(hass: HomeAssistant) -> None:\n    """Test derivative sensor state."""\n    await setup_tests(\n        hass,\n        {"unit_time": UnitOfTime.SECONDS},\n        times=[20, 30],\n        values=[5, 5],\n        expected_state=0,\n    )\n\n\nasync def test_dataSet5(hass: HomeAssistant) -> None:\n    """Test derivative sensor state."""\n    await setup_tests(\n        hass,\n        {"unit_time": UnitOfTime.SECONDS},\n        times=[20, 30],\n        values=[10, -10],\n        expected_state=-2,\n    )\n\n\nasync def test_dataSet6(hass: HomeAssistant) -> None:\n    """Test derivative sensor state."""\n    await setup_tests(hass, {}, times=[0, 60], values=[0, 1 / 60], expected_state=1)\n\n\n# Test unchanged states work both with and without max_sub_interval\n@pytest.mark.parametrize("extra_config", [{}, {"max_sub_interval": {"minutes": 9999}}])\n@pytest.mark.parametrize("force_update", [False, True])\n@pytest.mark.parametrize(\n    "attributes",\n    [\n        # Same attributes, fires state report\n        [A1, A1] * 10 + [A1],\n        # Changing attributes, fires state change with bumped last_updated\n        [A1, A2] * 10 + [A1],\n    ],\n)\nasync def test_data_moving_average_with_zeroes(\n    hass: HomeAssistant,\n    extra_config: dict[str, Any],\n    force_update: bool,\n    attributes: list[dict[str, Any]],\n) -> None:\n    """Test that zeroes are properly handled within the time window."""\n    # We simulate the following situation:\n    # The temperature rises 1 °C per minute for 10 minutes long. Then, it\n    # stays constant for another 10 minutes. There is a data point every\n    # minute and we use a time window of 10 minutes.\n    # Therefore, we can expect the derivative to peak at 1 after 10 minutes\n    # and then fall down to 0 in steps of 10%.\n\n    events: list[Event[EventStateChangedData]] = []\n\n    @callback\n    def _capture_event(event: Event) -> None:\n        events.append(event)\n\n    async_track_state_change_event(hass, "sensor.power", _capture_event)\n\n    temperature_values = []\n    for temperature in range(10):\n        temperature_values += [temperature]\n    temperature_values += [10] * 11\n    time_window = 600\n    times = list(range(0, 1200 + 60, 60))\n\n    config, entity_id = await _setup_sensor(\n        hass,\n        {\n            "time_window": {"seconds": time_window},\n            "unit_time": UnitOfTime.MINUTES,\n            "round": 1,\n        }\n        | extra_config,\n    )\n\n    base = dt_util.utcnow()\n    with freeze_time(base) as freezer:\n        last_derivative = 0\n        for time, value, extra_attributes in zip(\n            times, temperature_values, attributes, strict=True\n        ):\n            now = base + timedelta(seconds=time)\n            freezer.move_to(now)\n            hass.states.async_set(\n                entity_id, value, extra_attributes, force_update=force_update\n            )\n\n    await hass.async_block_till_done()\n    await hass.async_block_till_done()\n\n    assert len(events[2:]) == len(times)\n    for time, event in zip(times, events[2:], strict=True):\n        state = event.data["new_state"]\n        derivative = round(float(state.state), config["sensor"]["round"])\n\n        if time_window == time:\n            assert derivative == 1.0\n        elif time_window < time < time_window * 2:\n            assert (0.1 - 1e-6) < abs(derivative - last_derivative) < (0.1 + 1e-6)\n        elif time == time_window * 2:\n            assert derivative == 0\n\n        last_derivative = derivative\n\n\nasync def test_data_moving_average_for_discrete_sensor(hass: HomeAssistant) -> None:\n    """Test derivative sensor state."""\n    # We simulate the following situation:\n    # The temperature rises 1 °C per minute for 30 minutes long.\n    # There is a data point every 30 seconds, however, the sensor returns\n    # the temperature rounded down to an integer value.\n    # We use a time window of 10 minutes and therefore we can expect\n    # (because the true derivative is 1 °C/min) an error of less than 10%.\n\n    temperature_values = []\n    for temperature in range(30):\n        temperature_values += [temperature] * 2  # two values per minute\n    time_window = 600\n    times = list(range(0, 1800, 30))\n\n    config, entity_id = await _setup_sensor(\n        hass,\n        {\n            "time_window": {"seconds": time_window},\n            "unit_time": UnitOfTime.MINUTES,\n            "round": 1,\n        },\n    )  # two minute window\n\n    base = dt_util.utcnow()\n    with freeze_time(base) as freezer:\n        for time, value in zip(times, temperature_values, strict=True):\n            now = base + timedelta(seconds=time)\n            freezer.move_to(now)\n            hass.states.async_set(entity_id, value, {})\n            await hass.async_block_till_done()\n\n            if time_window < time < times[-1] - time_window:\n                state = hass.states.get("sensor.power")\n                derivative = round(float(state.state), config["sensor"]["round"])\n                # Test that the error is never more than\n                # (time_window_in_minutes / true_derivative * 100) = 10% + ε\n                assert abs(1 - derivative) <= 0.1 + 1e-6\n\n\nasync def test_data_moving_average_for_irregular_times(hass: HomeAssistant) -> None:\n    """Test derivative sensor state."""\n    # We simulate the following situation:\n    # The temperature rises 1 °C per minute for 30 minutes long.\n    # There is 60 random datapoints (and the start and end) and the signal is normally distributed\n    # around the expected value with ±0.1°C\n    # We use a time window of 1 minute and expect an error of less than the standard deviation. (0.01)\n\n    time_window = 60\n    random.seed(0)\n    times = sorted(random.sample(range(1800), 60))\n\n    def temp_function(time):\n        random.seed(0)\n        temp = time / (600)\n        return random.gauss(temp, 0.1)\n\n    temperature_values = list(map(temp_function, times))\n\n    config, entity_id = await _setup_sensor(\n        hass,\n        {\n            "time_window": {"seconds": time_window},\n            "unit_time": UnitOfTime.MINUTES,\n            "round": 3,\n        },\n    )\n\n    base = dt_util.utcnow()\n    with freeze_time(base) as freezer:\n        for time, value in zip(times, temperature_values, strict=True):\n            now = base + timedelta(seconds=time)\n            freezer.move_to(now)\n            hass.states.async_set(entity_id, value, {})\n            await hass.async_block_till_done()\n\n            if time_window < time and time > times[3]:\n                state = hass.states.get("sensor.power")\n                derivative = round(float(state.state), config["sensor"]["round"])\n                # Test that the error is never more than\n                # (time_window_in_minutes / true_derivative * 100) = 10% + ε\n                assert abs(0.1 - derivative) <= 0.01 + 1e-6\n\n\nasync def test_double_signal_after_delay(hass: HomeAssistant) -> None:\n    """Test derivative sensor state."""\n    # The old algorithm would produce extreme values if, after a delay longer than the time window\n    # there would be two signals, a large spike would be produced. Check explicitly for this situation\n    time_window = 60\n    times = [*range(time_window * 10), time_window * 20, time_window * 20 + 0.01]\n\n    # just apply sine as some sort of temperature change and make sure the change after the delay is very small\n    temperature_values = [sin(x) for x in times]\n    temperature_values[-2] = temperature_values[-3] + 0.01\n    temperature_values[-1] = temperature_values[-2] + 0.01\n\n    config, entity_id = await _setup_sensor(\n        hass,\n        {\n            "time_window": {"seconds": time_window},\n            "unit_time": UnitOfTime.MINUTES,\n            "round": 3,\n        },\n    )\n\n    base = dt_util.utcnow()\n    previous = 0\n    with freeze_time(base) as freezer:\n        for time, value in zip(times, temperature_values, strict=True):\n            now = base + timedelta(seconds=time)\n            freezer.move_to(now)\n            hass.states.async_set(entity_id, value, {})\n            await hass.async_block_till_done()\n            state = hass.states.get("sensor.power")\n            derivative = round(float(state.state), config["sensor"]["round"])\n            if time == times[-1]:\n                # Test that the error is never more than\n                # (time_window_in_minutes / true_derivative * 100) = 10% + ε\n                assert abs(previous - derivative) <= 0.01 + 1e-6\n            previous = derivative\n\n\nasync def test_sub_intervals_instantaneous(hass: HomeAssistant) -> None:\n    """Test derivative sensor state."""\n    # We simulate the following situation:\n    # Value changes from 0 to 10 in 5 seconds (derivative = 2)\n    # The max_sub_interval is 20 seconds\n    # After max_sub_interval elapses, derivative should change to 0\n    # Value changes to 0, 35 seconds after changing to 10 (derivative = -10/35 = -0.29)\n    # State goes unavailable, derivative stops changing after that.\n    # State goes back to 0, derivative returns to 0 after a max_sub_interval\n\n    max_sub_interval = 20\n\n    config, entity_id = await _setup_sensor(\n        hass,\n        {\n            "unit_time": UnitOfTime.SECONDS,\n            "round": 2,\n            "max_sub_interval": {"seconds": max_sub_interval},\n        },\n    )\n\n    base = dt_util.utcnow()\n    with freeze_time(base) as freezer:\n        freezer.move_to(base)\n        hass.states.async_set(entity_id, 0, {}, force_update=True)\n        await hass.async_block_till_done()\n\n        now = base + timedelta(seconds=5)\n        freezer.move_to(now)\n        hass.states.async_set(entity_id, 10, {}, force_update=True)\n        await hass.async_block_till_done()\n\n        state = hass.states.get("sensor.power")\n        derivative = round(float(state.state), config["sensor"]["round"])\n        assert derivative == 2\n\n        # No change yet as sub_interval not elapsed\n        now += timedelta(seconds=15)\n        async_fire_time_changed(hass, now)\n        await hass.async_block_till_done()\n\n        state = hass.states.get("sensor.power")\n        derivative = round(float(state.state), config["sensor"]["round"])\n        assert derivative == 2\n\n        # After 5 more seconds the sub_interval should fire and derivative should be 0\n        now += timedelta(seconds=10)\n        async_fire_time_changed(hass, now)\n        await hass.async_block_till_done()\n\n        state = hass.states.get("sensor.power")\n        derivative = round(float(state.state), config["sensor"]["round"])\n        assert derivative == 0\n\n        now += timedelta(seconds=10)\n        freezer.move_to(now)\n        hass.states.async_set(entity_id, 0, {}, force_update=True)\n        await hass.async_block_till_done()\n\n        state = hass.states.get("sensor.power")\n        derivative = round(float(state.state), config["sensor"]["round"])\n        assert derivative == -0.29\n\n        now += timedelta(seconds=10)\n        freezer.move_to(now)\n        hass.states.async_set(entity_id, STATE_UNAVAILABLE, {}, force_update=True)\n        await hass.async_block_till_done()\n\n        state = hass.states.get("sensor.power")\n        assert state.state == STATE_UNAVAILABLE\n\n        now += timedelta(seconds=60)\n        async_fire_time_changed(hass, now)\n        await hass.async_block_till_done()\n\n        state = hass.states.get("sensor.power")\n        assert state.state == STATE_UNAVAILABLE\n\n        now += timedelta(seconds=10)\n        freezer.move_to(now)\n        hass.states.async_set(entity_id, 0, {}, force_update=True)\n        await hass.async_block_till_done()\n\n        state = hass.states.get("sensor.power")\n        derivative = round(float(state.state), config["sensor"]["round"])\n        assert derivative == 0\n\n        now += timedelta(seconds=max_sub_interval + 1)\n        async_fire_time_changed(hass, now)\n        await hass.async_block_till_done()\n\n        state = hass.states.get("sensor.power")\n        derivative = round(float(state.state), config["sensor"]["round"])\n        assert derivative == 0\n\n\nasync def test_sub_intervals_with_time_window(hass: HomeAssistant) -> None:\n    """Test derivative sensor state."""\n    # We simulate the following situation:\n    # The value rises by 1 every second for 1 minute, then pauses\n    # The time window is 30 seconds\n    # The max_sub_interval is 5 seconds\n    # After the value stops increasing, the derivative should slowly trend back to 0\n\n    values = []\n    for value in range(60):\n        values += [value]\n    time_window = 30\n    max_sub_interval = 5\n    times = values\n\n    config, entity_id = await _setup_sensor(\n        hass,\n        {\n            "time_window": {"seconds": time_window},\n            "unit_time": UnitOfTime.SECONDS,\n            "round": 2,\n            "max_sub_interval": {"seconds": max_sub_interval},\n        },\n    )\n\n    base = dt_util.utcnow()\n    with freeze_time(base) as freezer:\n        last_state_change = None\n        for time, value in zip(times, values, strict=True):\n            now = base + timedelta(seconds=time)\n            freezer.move_to(now)\n            hass.states.async_set(entity_id, value, {}, force_update=True)\n            last_state_change = now\n            await hass.async_block_till_done()\n\n            if time_window < time:\n                state = hass.states.get("sensor.power")\n                derivative = round(float(state.state), config["sensor"]["round"])\n                # Test that the error is never more than\n                # (time_window_in_minutes / true_derivative * 100) = 1% + ε\n                assert abs(1 - derivative) <= 0.01 + 1e-6\n\n        for time in range(60):\n            now = last_state_change + timedelta(seconds=time)\n            freezer.move_to(now)\n\n            async_fire_time_changed(hass, now)\n            await hass.async_block_till_done()\n\n            state = hass.states.get("sensor.power")\n            derivative = round(float(state.state), config["sensor"]["round"])\n\n            def calc_expected(elapsed_seconds: int, calculation_delay: int = 0):\n                last_sub_interval = (\n                    elapsed_seconds // max_sub_interval\n                ) * max_sub_interval\n                return (\n                    0\n                    if (last_sub_interval >= time_window)\n                    else (\n                        (time_window - last_sub_interval - calculation_delay)\n                        / time_window\n                    )\n                )\n\n            rounding_err = 0.01 + 1e-6\n            expect_max = calc_expected(time) + rounding_err\n            # Allow one second of slop for internal delays\n            expect_min = calc_expected(time, 1) - rounding_err\n\n            assert expect_min <= derivative <= expect_max, f"Failed at time {time}"\n\n\nasync def test_prefix(hass: HomeAssistant) -> None:\n    """Test derivative sensor state using a power source."""\n    config = {\n        "sensor": {\n            "platform": "derivative",\n            "name": "derivative",\n            "source": "sensor.power",\n            "round": 2,\n            "unit_prefix": "k",\n        }\n    }\n\n    assert await async_setup_component(hass, "sensor", config)\n\n    entity_id = config["sensor"]["source"]\n    base = dt_util.utcnow()\n    with freeze_time(base) as freezer:\n        hass.states.async_set(\n            entity_id,\n            1000,\n            {"unit_of_measurement": UnitOfPower.WATT},\n        )\n        await hass.async_block_till_done()\n\n        freezer.move_to(dt_util.utcnow() + timedelta(seconds=3600))\n        hass.states.async_set(\n            entity_id,\n            2000,\n            {"unit_of_measurement": UnitOfPower.WATT},\n        )\n        await hass.async_block_till_done()\n\n    state = hass.states.get("sensor.derivative")\n    assert state is not None\n\n    # Testing a power sensor increasing by 1000 Watts per hour = 1kW/h\n    assert round(float(state.state), config["sensor"]["round"]) == 1.0\n    assert state.attributes.get("unit_of_measurement") == f"kW/{UnitOfTime.HOURS}"\n\n\nasync def test_suffix(hass: HomeAssistant) -> None:\n    """Test derivative sensor state using a network counter source."""\n    config = {\n        "sensor": {\n            "platform": "derivative",\n            "name": "derivative",\n            "source": "sensor.bytes_per_second",\n            "round": 2,\n            "unit_prefix": "k",\n            "unit_time": UnitOfTime.SECONDS,\n        }\n    }\n\n    assert await async_setup_component(hass, "sensor", config)\n\n    entity_id = config["sensor"]["source"]\n    base = dt_util.utcnow()\n    with freeze_time(base) as freezer:\n        hass.states.async_set(entity_id, 1000, {})\n        await hass.async_block_till_done()\n\n        freezer.move_to(dt_util.utcnow() + timedelta(seconds=3600))\n        hass.states.async_set(entity_id, 1000, {})\n        await hass.async_block_till_done()\n\n    state = hass.states.get("sensor.derivative")\n    assert state is not None\n\n    # Testing a network speed sensor at 1000 bytes/s over 10s  = 10kbytes/s2\n    assert round(float(state.state), config["sensor"]["round"]) == 0.0\n\n\nasync def test_total_increasing_reset(hass: HomeAssistant) -> None:\n    """Test derivative sensor state with total_increasing sensor input where it should ignore the reset value."""\n    times = [0, 20, 30, 35, 40, 50, 60]\n    values = [0, 10, 30, 40, 0, 10, 40]\n    expected_times = [0, 20, 30, 35, 50, 60]\n    expected_values = ["0.00", "0.50", "2.00", "2.00", "1.00", "3.00"]\n\n    _config, entity_id = await _setup_sensor(hass, {"unit_time": UnitOfTime.SECONDS})\n\n    base_time = dt_util.utcnow()\n    actual_times = []\n    actual_values = []\n    with freeze_time(base_time) as freezer:\n        for time, value in zip(times, values, strict=True):\n            current_time = base_time + timedelta(seconds=time)\n            freezer.move_to(current_time)\n            hass.states.async_set(\n                entity_id,\n                value,\n                {ATTR_STATE_CLASS: SensorStateClass.TOTAL_INCREASING},\n            )\n            await hass.async_block_till_done()\n\n            state = hass.states.get("sensor.power")\n            assert state is not None\n\n            if state.last_reported == current_time:\n                actual_times.append(time)\n                actual_values.append(state.state)\n\n    assert actual_times == expected_times\n    assert actual_values == expected_values\n\n\nasync def test_device_id(\n    hass: HomeAssistant,\n    entity_registry: er.EntityRegistry,\n    device_registry: dr.DeviceRegistry,\n) -> None:\n    """Test for source entity device for Derivative."""\n    source_config_entry = MockConfigEntry()\n    source_config_entry.add_to_hass(hass)\n    source_device_entry = device_registry.async_get_or_create(\n        config_entry_id=source_config_entry.entry_id,\n        identifiers={("sensor", "identifier_test")},\n        connections={("mac", "30:31:32:33:34:35")},\n    )\n    source_entity = entity_registry.async_get_or_create(\n        "sensor",\n        "test",\n        "source",\n        config_entry=source_config_entry,\n        device_id=source_device_entry.id,\n    )\n    await hass.async_block_till_done()\n    assert entity_registry.async_get("sensor.test_source") is not None\n\n    derivative_config_entry = MockConfigEntry(\n        data={},\n        domain=DOMAIN,\n        options={\n            "name": "Derivative",\n            "round": 1.0,\n            "source": "sensor.test_source",\n            "time_window": {"seconds": 0.0},\n            "unit_prefix": "k",\n            "unit_time": "min",\n        },\n        title="Derivative",\n    )\n\n    derivative_config_entry.add_to_hass(hass)\n\n    assert await hass.config_entries.async_setup(derivative_config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    derivative_entity = entity_registry.async_get("sensor.derivative")\n    assert derivative_entity is not None\n    assert derivative_entity.device_id == source_entity.device_id\n\n\n@pytest.mark.parametrize("bad_state", [STATE_UNAVAILABLE, STATE_UNKNOWN, "foo"])\nasync def test_unavailable(\n    bad_state: str,\n    hass: HomeAssistant,\n) -> None:\n    """Test derivative sensor state when unavailable."""\n    config, entity_id = await _setup_sensor(hass, {"unit_time": "s"})\n\n    times = [0, 1, 2, 3]\n    values = [0, 1, bad_state, 2]\n    expected_state = [\n        0,\n        1,\n        STATE_UNAVAILABLE if bad_state == STATE_UNAVAILABLE else STATE_UNKNOWN,\n        0.5,\n    ]\n\n    # Testing a energy sensor with non-monotonic intervals and values\n    base = dt_util.utcnow()\n    with freeze_time(base) as freezer:\n        for time, value, expect in zip(times, values, expected_state, strict=True):\n            freezer.move_to(base + timedelta(seconds=time))\n            hass.states.async_set(entity_id, value, {})\n            await hass.async_block_till_done()\n\n            state = hass.states.get("sensor.power")\n            assert state is not None\n            rounded_state = (\n                state.state\n                if expect in [STATE_UNKNOWN, STATE_UNAVAILABLE]\n                else round(float(state.state), config["sensor"]["round"])\n            )\n            assert rounded_state == expect\n\n\n@pytest.mark.parametrize("bad_state", [STATE_UNAVAILABLE, STATE_UNKNOWN, "foo"])\nasync def test_unavailable_2(\n    bad_state: str,\n    hass: HomeAssistant,\n) -> None:\n    """Test derivative sensor state when unavailable with a time window."""\n    config, entity_id = await _setup_sensor(\n        hass, {"unit_time": "s", "time_window": {"seconds": 10}}\n    )\n\n    # Monotonically increasing by 1, with some unavailable holes\n    times = list(range(21))\n    values = list(range(21))\n    values[3] = bad_state\n    values[6] = bad_state\n    values[7] = bad_state\n    values[8] = bad_state\n\n    base = dt_util.utcnow()\n    with freeze_time(base) as freezer:\n        for time, value in zip(times, values, strict=True):\n            freezer.move_to(base + timedelta(seconds=time))\n            hass.states.async_set(entity_id, value, {})\n            await hass.async_block_till_done()\n\n            state = hass.states.get("sensor.power")\n            assert state is not None\n\n            if value == bad_state:\n                assert (\n                    state.state == STATE_UNAVAILABLE\n                    if bad_state is STATE_UNAVAILABLE\n                    else STATE_UNKNOWN\n                )\n            else:\n                expect = (time / 10) if time < 10 else 1\n                assert round(float(state.state), config["sensor"]["round"]) == round(\n                    expect, config["sensor"]["round"]\n                )\n\n\n@pytest.mark.parametrize("restore_state", ["3.00", STATE_UNKNOWN])\nasync def test_unavailable_boot(\n    restore_state,\n    hass: HomeAssistant,\n) -> None:\n    """Test that the booting sequence does not leave derivative in a bad state."""\n\n    mock_restore_cache_with_extra_data(\n        hass,\n        [\n            (\n                State(\n                    "sensor.power",\n                    restore_state,\n                    {\n                        "unit_of_measurement": "W",\n                    },\n                ),\n                {\n                    "native_value": restore_state,\n                    "native_unit_of_measurement": "W",\n                },\n            ),\n        ],\n    )\n\n    config = {\n        "platform": "derivative",\n        "name": "power",\n        "source": "sensor.energy",\n        "round": 2,\n        "unit_time": "s",\n    }\n\n    config = {"sensor": config}\n    entity_id = config["sensor"]["source"]\n    hass.states.async_set(entity_id, STATE_UNAVAILABLE, {})\n    await hass.async_block_till_done()\n\n    assert await async_setup_component(hass, "sensor", config)\n    await hass.async_block_till_done()\n\n    state = hass.states.get("sensor.power")\n    assert state is not None\n    # Sensor is unavailable as source is unavailable\n    assert state.state == STATE_UNAVAILABLE\n\n    base = dt_util.utcnow()\n    with freeze_time(base) as freezer:\n        freezer.move_to(base + timedelta(seconds=1))\n        hass.states.async_set(entity_id, 10, {})\n        await hass.async_block_till_done()\n\n        state = hass.states.get("sensor.power")\n        assert state is not None\n        # The source sensor has moved to a valid value, but we need 2 points to derive,\n        # so just hold until the next tick\n        assert state.state == restore_state\n\n        freezer.move_to(base + timedelta(seconds=2))\n        hass.states.async_set(entity_id, 15, {})\n        await hass.async_block_till_done()\n\n        state = hass.states.get("sensor.power")\n        assert state is not None\n        # Now that the source sensor has two valid datapoints, we can calculate derivative\n        assert state.state == "5.00"\n\n\nasync def test_source_unit_change(\n    hass: HomeAssistant,\n) -> None:\n    """Test how derivative responds when the source sensor changes unit."""\n    source_id = "sensor.source"\n    config = {\n        "sensor": {\n            "platform": "derivative",\n            "name": "derivative",\n            "source": source_id,\n            "unit_time": "s",\n        }\n    }\n\n    assert await async_setup_component(hass, "sensor", config)\n    await hass.async_block_till_done()\n    entity_id = "sensor.derivative"\n\n    state = hass.states.get(entity_id)\n    assert state.state == STATE_UNAVAILABLE\n    assert state.attributes.get("unit_of_measurement") is None\n\n    time = dt_util.utcnow()\n    with freeze_time(time) as freezer:\n        # First state update of the source.\n        # Derivative does not learn the UoM yet.\n        hass.states.async_set(source_id, "5", {"unit_of_measurement": "cats"})\n        await hass.async_block_till_done()\n        state = hass.states.get(entity_id)\n        assert state.state == "0.000"\n        assert state.attributes.get("unit_of_measurement") is None\n\n        # Second state update of the source.\n        time += timedelta(seconds=1)\n        freezer.move_to(time)\n        hass.states.async_set(source_id, "7", {"unit_of_measurement": "cats"})\n        await hass.async_block_till_done()\n        state = hass.states.get(entity_id)\n        assert state.state == "2.000"\n        assert state.attributes.get("unit_of_measurement") == "cats/s"\n\n        # Third state update of the source, source unit changes to dogs.\n        # Ignored by derivative which continues reporting cats.\n        time += timedelta(seconds=1)\n        freezer.move_to(time)\n        hass.states.async_set(source_id, "12", {"unit_of_measurement": "dogs"})\n        await hass.async_block_till_done()\n        state = hass.states.get(entity_id)\n        assert state.state == "5.000"\n        assert state.attributes.get("unit_of_measurement") == "cats/s"\n\n        # Fourth state update of the source, still dogs.\n        # Ignored by derivative which continues reporting cats.\n        time += timedelta(seconds=1)\n        freezer.move_to(time)\n        hass.states.async_set(source_id, "20", {"unit_of_measurement": "dogs"})\n        await hass.async_block_till_done()\n        state = hass.states.get(entity_id)\n        assert state.state == "8.000"\n        assert state.attributes.get("unit_of_measurement") == "cats/s"\n',
        }
